export const MetadataDisplay: React.FC<MetadataDisplayProps> = ({ metadata, reviewMarkdown }) => {
  if (!metadata) return null;

  const fullMarkdown = metadata.post_markdown_lines?.join('\n') ?? reviewMarkdown;

  const reviewSchemaLd = {
    "@context": "https://schema.org",
    "@type": "Review",
    "itemReviewed": {
        "@type": "Product",
        "name": metadata.review_schema.itemReviewed.name,
        "description": metadata.review_schema.itemReviewed.description,
        "image": metadata.feature_image_url
    },
    "reviewRating": {
        "@type": "Rating",
        "ratingValue": metadata.review_schema.reviewRating.ratingValue,
        "bestRating": metadata.review_schema.reviewRating.bestRating
    },
    "author": {
        "@type": "Person",
        "name": metadata.review_schema.author.name
    },
    "positiveNotes": {
        "@type": "ItemList",
        "itemListElement": metadata.review_schema.positiveNotes.map((note, index) => ({ "@type": "ListItem", "position": index + 1, "name": note }))
    },
    "negativeNotes": {
        "@type": "ItemList",
        "itemListElement": metadata.review_schema.negativeNotes.map((note, index) => ({ "@type": "ListItem", "position": index + 1, "name": note }))
    }
  };

  const faqSchemaLd = {
      "@context": "https://schema.org",
      "@type": "FAQPage",
      "mainEntity": metadata.faq_schema.map(faq => ({
          "@type": "Question",
          "name": faq.question,
          "acceptedAnswer": {
              "@type": "Answer",
              "text": faq.answer
          }
      }))
  };

  const jsonLdScript = `<script type="application/ld+json">
${JSON.stringify([reviewSchemaLd, faqSchemaLd], null, 2)}
</script>`;

  const allMetadataText = `Meta Title: ${metadata.meta_title}
Meta Description: ${metadata.meta_description}
Slug: ${metadata.slug}
Feature Image: ${metadata.feature_image_url}

${jsonLdScript}`;

  return (
    <div className="mt-8 pt-6 border-t border-gray-200">
      <div className="flex justify-between items-center mb-4">
        <h3 className="text-lg font-bold text-brand-charcoal">Ghost CMS Publishing Pack</h3>
        <CopyButton 
            textToCopy={allMetadataText} 
            label="Copy All Metadata" 
            className="px-4 py-2 text-sm font-semibold text-white bg-brand-primary hover:bg-brand-primary-dark rounded-md shadow-sm transition-colors"
        />
      </div>
      <div className="space-y-6">
        <div>
            <h4 className="font-semibold text-brand-secondary">SEO & Post Data</h4>
            <div className="mt-2 p-4 bg-gray-50 rounded-lg text-sm space-y-2">
                <p><strong>Meta Title:</strong> {metadata.meta_title}</p>
                <p><strong>Meta Description:</strong> {metadata.meta_description}</p>
                <p><strong>Slug:</strong> {metadata.slug}</p>
                <p><strong>Feature Image:</strong> <a href={metadata.feature_image_url} className="text-blue-600 hover:underline" target="_blank" rel="noopener noreferrer">Link</a></p>
            </div>
        </div>

        <div>
            <div className="flex justify-between items-center mb-2">
                <h4 className="font-semibold text-brand-secondary">Full Post Markdown</h4>
                <CopyButton textToCopy={fullMarkdown} />
            </div>
            <textarea
                readOnly
                value={fullMarkdown}
                className="w-full h-48 p-2 font-mono text-xs border border-gray-300 rounded-md bg-gray-50"
            />
        </div>

        <div>
            <div className="flex justify-between items-center mb-2">
                <h4 className="font-semibold text-brand-secondary">Structured Data (JSON-LD)</h4>
                <CopyButton textToCopy={jsonLdScript} />
            </div>
             <p className="text-xs text-gray-500 mb-2">Paste this into an HTML card in Ghost.</p>
            <textarea
                readOnly
                value={jsonLdScript}
                className="w-full h-48 p-2 font-mono text-xs border border-gray-300 rounded-md bg-gray-50"
            />
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { BASE_PROMPT, FACT_CHECK_PROMPT, PUBLISHING_PACK_PROMPT, ARTICLE_OUTLINE_PROMPT, ARTICLE_GENERATION_PROMPT } from '../constants';
import type { GroundingMetadata, Metadata } from '../types';

if (!process.env.API_KEY) {
    console.error("API_KEY environment variable not set.");
}

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY! });
const model = 'gemini-2.5-flash';

// Helper function to convert a File to a base64 string
const fileToGenerativePart = async (file: File) => {
    const base64EncodedDataPromise = new Promise<string>((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(file);
    });
    return {
        inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
    };
};

export async function generateReview(bikeName: string, imageFile: File | null): Promise<{ review: string, grounding_metadata: GroundingMetadata | null }> {
    const parts: any[] = [
        { text: BASE_PROMPT }
    ];

    if (imageFile) {
        const imagePart = await fileToGenerativePart(imageFile);
        parts.push(imagePart);
        parts.push({text: `\n\nIdentify the e-bike in the image and generate the review.`});
    } else {
        parts.push({ text: `\n\nE-Bike Model: ${bikeName}` });
    }

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: { parts },
            config: {
                tools: [{ googleSearch: {} }],
            }
        });

        const review = response.text;
        const grounding_metadata = response.candidates?.[0]?.groundingMetadata as GroundingMetadata | null;

        return { review, grounding_metadata };
    } catch (error: any) {
        console.error("Error generating review:", error);
        throw new Error(`Failed to generate review: ${error.message}`);
    }
}

export async function factCheckReview(reviewMarkdown: string): Promise<{ report: string, refinedReview: string, grounding_metadata: GroundingMetadata | null }> {
    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: `${FACT_CHECK_PROMPT}\n\n${reviewMarkdown}`,
            config: {
                tools: [{ googleSearch: {} }]
            }
        });

        const fullText = response.text;
        const separator = "---END-OF-REPORT---";
        const parts = fullText.split(separator);

        if (parts.length < 2) {
            console.warn("Fact-check report separator not found. Treating entire response as review.");
            return { report: "No report generated.", refinedReview: fullText, grounding_metadata: null };
        }

        const report = parts[0].trim();
        const refinedReview = parts.slice(1).join(separator).trim();
        const grounding_metadata = response.candidates?.[0]?.groundingMetadata as GroundingMetadata | null;

        return { report, refinedReview, grounding_metadata };
    } catch (error: any) {
        console.error("Error fact-checking review:", error);
        throw new Error(`Failed to fact-check review: ${error.message}`);
    }
}

export async function generateMetadata(reviewMarkdown: string): Promise<Metadata> {
    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: `${PUBLISHING_PACK_PROMPT}\n\n${reviewMarkdown}`,
            config: {
                responseMimeType: "application/json",
            }
        });

        const jsonText = response.text.trim();
        const metadata = JSON.parse(jsonText) as Metadata;
        return metadata;

    } catch (error: any) {
        console.error("Error generating metadata:", error);
        throw new Error(`Failed to generate metadata: ${error.message}`);
    }
}

export async function generateArticleOutline(topic: string, keywords: string, domain: string, context: string): Promise<string> {
    const prompt = `${ARTICLE_OUTLINE_PROMPT}

    Topic: ${topic}
    Keywords: ${keywords}
    Manufacturer Domain: ${domain}
    Context/Research Notes: ${context}
    `;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: prompt,
        });
        return response.text;
    } catch (error: any) {
         console.error("Error generating outline:", error);
        throw new Error(`Failed to generate outline: ${error.message}`);
    }
}

export async function generateFullArticle(outline: string, topic: string, domain: string, context: string, imageFile: File | null): Promise<{ article: string, grounding_metadata: GroundingMetadata | null }> {
    const parts: any[] = [
        { text: ARTICLE_GENERATION_PROMPT }
    ];

    const inputData = `
    Topic: ${topic}
    Manufacturer Domain: ${domain}
    Additional Context: ${context}

    APPROVED OUTLINE:
    ${outline}
    `;

    parts.push({ text: inputData });

    if (imageFile) {
        const imagePart = await fileToGenerativePart(imageFile);
        parts.push(imagePart);
        parts.push({ text: "Use this image for visual analysis and photo journalism description." });
    }

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: { parts },
            config: {
                tools: [{ googleSearch: {} }],
            }
        });

        return { 
            article: response.text, 
            grounding_metadata: response.candidates?.[0]?.groundingMetadata as GroundingMetadata | null 
        };
    } catch (error: any) {
        console.error("Error generating article:", error);
        throw new Error(`Failed to generate article: ${error.message}`);
    }
}

import React, { useState, useCallback } from 'react';

interface ArticleFormProps {
  onGenerateOutline: (data: ArticleFormData) => void;
  onGenerateArticle: (outline: string, data: ArticleFormData) => void;
  isLoading: boolean;
  outline: string | null;
}

export interface ArticleFormData {
  topic: string;
  keywords: string;
  domain: string;
  context: string;
  imageFile: File | null;
}

export const ArticleForm: React.FC<ArticleFormProps> = ({ onGenerateOutline, onGenerateArticle, isLoading, outline }) => {
  const [topic, setTopic] = useState('');
  const [keywords, setKeywords] = useState('');
  const [domain, setDomain] = useState('');
  const [context, setContext] = useState('');
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const [editedOutline, setEditedOutline] = useState<string>('');

  // Update local outline state when prop changes
  React.useEffect(() => {
    if (outline) setEditedOutline(outline);
  }, [outline]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleRemoveImage = () => {
    setImageFile(null);
    setImagePreview(null);
    const input = document.getElementById('article-image-upload') as HTMLInputElement;
    if (input) input.value = '';
  };

  const handleSubmitOutline = useCallback((e: React.FormEvent) => {
    e.preventDefault();
    if (!topic) {
      alert('Please provide an article topic.');
      return;
    }
    onGenerateOutline({ topic, keywords, domain, context, imageFile });
  }, [topic, keywords, domain, context, imageFile, onGenerateOutline]);

  const handleSubmitArticle = useCallback(() => {
    onGenerateArticle(editedOutline, { topic, keywords, domain, context, imageFile });
  }, [editedOutline, topic, keywords, domain, context, imageFile, onGenerateArticle]);

  return (
    <div className="space-y-6">
      {!outline ? (
        <form onSubmit={handleSubmitOutline} className="space-y-4">
          <div>
            <label htmlFor="article-topic" className="block text-sm font-medium text-brand-secondary mb-1">
              Article Topic / Title
            </label>
            <input
              type="text"
              id="article-topic"
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
              placeholder="e.g., 'Top 5 Commuter eBikes for 2025' or 'Understanding Voltages'"
              className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-brand-primary focus:border-brand-primary"
              disabled={isLoading}
            />
          </div>

          <div>
            <label htmlFor="article-keywords" className="block text-sm font-medium text-brand-secondary mb-1">
              Target Keywords (Silo Support)
            </label>
            <input
              type="text"
              id="article-keywords"
              value={keywords}
              onChange={(e) => setKeywords(e.target.value)}
              placeholder="e.g., ebike battery care, lithium ion safety"
              className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-brand-primary focus:border-brand-primary"
              disabled={isLoading}
            />
          </div>

          <div>
            <label htmlFor="article-domain" className="block text-sm font-medium text-brand-secondary mb-1">
              Manufacturer Domain (optional)
            </label>
            <input
              type="text"
              id="article-domain"
              value={domain}
              onChange={(e) => setDomain(e.target.value)}
              placeholder="e.g., radpowerbikes.com"
              className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-brand-primary focus:border-brand-primary"
              disabled={isLoading}
            />
          </div>

          <div>
            <label htmlFor="article-context" className="block text-sm font-medium text-brand-secondary mb-1">
              Paste Research / Notes / Context
            </label>
            <textarea
              id="article-context"
              value={context}
              onChange={(e) => setContext(e.target.value)}
              placeholder="Paste any previous research, specs, or specific points you want included..."
              className="w-full h-32 px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-brand-primary focus:border-brand-primary"
              disabled={isLoading}
            />
          </div>

          <div>
            <label htmlFor="article-image-upload" className="block text-sm font-medium text-brand-secondary mb-1">
              Upload eBike Image (for Photo Journalism analysis)
            </label>
            <input
              type="file"
              id="article-image-upload"
              accept="image/*"
              onChange={handleImageChange}
              className="w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-md file:border-0 file:text-sm file:font-semibold file:bg-brand-primary/10 file:text-brand-primary-dark hover:file:bg-brand-primary/20"
              disabled={isLoading}
            />
          </div>

          {imagePreview && (
            <div className="relative w-40 h-40 mt-2">
              <img src={imagePreview} alt="Preview" className="object-cover w-full h-full rounded-md border-2 border-brand-primary"/>
              <button
                type="button"
                onClick={handleRemoveImage}
                className="absolute -top-2 -right-2 bg-brand-error text-white rounded-full w-6 h-6 flex items-center justify-center text-sm font-bold shadow-md hover:bg-red-700"
                disabled={isLoading}
              >
                &times;
              </button>
            </div>
          )}

          <button
            type="submit"
            disabled={isLoading || !topic}
            className="w-full px-4 py-3 font-bold text-white bg-brand-primary rounded-md shadow-sm hover:bg-brand-primary-dark focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-primary disabled:bg-gray-400 disabled:cursor-not-allowed transition-colors"
          >
            {isLoading ? 'Thinking...' : 'Generate Outline'}
          </button>
        </form>
      ) : (
        <div className="space-y-4 animate-fade-in">
          <div className="flex justify-between items-center">
             <h3 className="text-lg font-bold text-brand-charcoal">Review & Edit Outline</h3>
             <button 
                onClick={() => setEditedOutline('')} // Reset outline to go back technically only if we cleared prop in parent, but simple text reset works for UI flow mostly
                className="text-sm text-gray-500 hover:text-brand-primary underline"
             >
                Start Over
             </button>
          </div>
          <p className="text-sm text-brand-secondary">Alex has generated this outline. Edit it to guide the final article.</p>
          <textarea
            value={editedOutline}
            onChange={(e) => setEditedOutline(e.target.value)}
            className="w-full h-64 px-3 py-2 font-mono text-sm border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-brand-primary focus:border-brand-primary bg-brand-bg"
            disabled={isLoading}
          />
           <button
            onClick={handleSubmitArticle}
            disabled={isLoading}
