// This dynamic import is necessary because these are not standard dependencies.
// They are loaded from a CDN via an import map in index.html.
const loadJspdf = () => import('jspdf');
const loadHtml2canvas = () => import('html2canvas');

export function getFileNameBase(reviewMarkdown: string | null): string {
    if (reviewMarkdown) {
       // Try specific review format first (e.g. "# ModelName Review")
       const reviewTitleMatch = reviewMarkdown.match(/^# (.*?)(?::|\sReview)/);
       if (reviewTitleMatch && reviewTitleMatch[1]) {
           return `${reviewTitleMatch[1].toLowerCase().replace(/[^a-z0-9]+/g, '-')}`;
       }

       // Fallback: Use the entire H1 content if it doesn't match the specific review pattern
       // This supports generic articles like "# The Safety Guide to Batteries"
       const h1Match = reviewMarkdown.match(/^# (.*)$/m);
       if (h1Match && h1Match[1]) {
           return h1Match[1].trim().toLowerCase().replace(/[^a-z0-9]+/g, '-');
       }
    }
    return "generated-content";
}

export function downloadFile(content: string, fileName: string, mimeType: string) {
    const blob = new Blob([content], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

export async function downloadPdf(element: HTMLElement, fileNameBase: string) {
    const loadingIndicator = document.createElement('div');
    loadingIndicator.innerText = 'Generating PDF...';
    loadingIndicator.className = 'fixed top-4 right-4 bg-brand-primary text-white p-3 rounded-lg shadow-lg z-50';
    document.body.appendChild(loadingIndicator);

    try {
        const { jsPDF } = await loadJspdf();
        const html2canvas = (await loadHtml2canvas()).default;

        const pdf = new jsPDF("p", "pt", "a4");
        const canvas = await html2canvas(element, { 
            scale: 2, 
            useCORS: true, 
            logging: false,
            backgroundColor: '#ffffff' // Ensure canvas background is white
        });

        const imgData = canvas.toDataURL("image/jpeg", 1.0);
        const imgWidth = pdf.internal.pageSize.getWidth();
        const pageHeight = pdf.internal.pageSize.getHeight();
        const imgHeight = (canvas.height * imgWidth) / canvas.width;
        let heightLeft = imgHeight;
        let position = 0;

        pdf.addImage(imgData, "JPEG", 0, position, imgWidth, imgHeight);
        heightLeft -= pageHeight;

        while (heightLeft >= 0) {
            position = heightLeft - imgHeight;
            pdf.addPage();
            pdf.addImage(imgData, "JPEG", 0, position, imgWidth, imgHeight);
            heightLeft -= pageHeight;
        }

        pdf.save(`${fileNameBase}.pdf`);
    } catch (err: any) {
        console.error("Error generating PDF:", err);
        alert(`Failed to generate PDF: ${err.message}`);
    } finally {
        document.body.removeChild(loadingIndicator);
    }
}

import React, { useState, useCallback } from 'react';
import { Header } from './components/Header';
import { ReviewForm } from './components/ReviewForm';
import { ArticleForm, ArticleFormData } from './components/ArticleForm';
import { Loader } from './components/Loader';
import { ErrorDisplay } from './components/ErrorDisplay';
import { FactCheckReport } from './components/FactCheckReport';
import { ReviewOutput } from './components/ReviewOutput';
import { ActionButtons } from './components/ActionButtons';
import { SourceList } from './components/SourceList';
import { MetadataDisplay } from './components/MetadataDisplay';
import { generateReview, factCheckReview, generateMetadata, generateArticleOutline, generateFullArticle } from './services/geminiService';
import type { GroundingMetadata, Metadata } from './types';
import { downloadFile, downloadPdf, getFileNameBase } from './utils/download';

type AppMode = 'review' | 'article';

function App() {
  const [mode, setMode] = useState<AppMode>('review');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');
  const [error, setError] = useState<string | null>(null);

  // Review Mode State
  const [reviewMarkdown, setReviewMarkdown] = useState<string | null>(null);
  const [factCheckReport, setFactCheckReport] = useState<string | null>(null);
  const [groundingMetadata, setGroundingMetadata] = useState<GroundingMetadata | null>(null);
  const [metadata, setMetadata] = useState<Metadata | null>(null);
  const [isEditing, setIsEditing] = useState<boolean>(false);
  const [currentImage, setCurrentImage] = useState<string | null>(null);

  // Article Mode State
  const [articleOutline, setArticleOutline] = useState<string | null>(null);

  const clearResults = () => {
    setError(null);
    setReviewMarkdown(null);
    setFactCheckReport(null);
    setGroundingMetadata(null);
    setMetadata(null);
    setIsEditing(false);
    setArticleOutline(null);
    setCurrentImage(null);
  };

  const handleModeSwitch = (newMode: AppMode) => {
    if (newMode !== mode) {
        setMode(newMode);
        // Optional: clear results on switch or keep them? 
        // Keeping them allows user to switch back and forth without losing work immediately.
        setError(null);
    }
  };

  const fileToDataUrl = (file: File): Promise<string> => {
    return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
    });
  };

  const handleGenerateReview = useCallback(async (bikeName: string, imageFile: File | null) => {
    clearResults();
    setIsLoading(true);
    setLoadingMessage('Researching and writing your review...');

    if (!process.env.API_KEY) {
        setError("API_KEY environment variable not set. Please configure it to use the application.");
        setIsLoading(false);
        return;
    }

    if (imageFile) {
        const dataUrl = await fileToDataUrl(imageFile);
        setCurrentImage(dataUrl);
    }

    try {
      const { review, grounding_metadata } = await generateReview(bikeName, imageFile);
      setReviewMarkdown(review);
      setGroundingMetadata(grounding_metadata);
      setLoadingMessage('Generating publishing pack...');
      const generatedMetadata = await generateMetadata(review);
      setMetadata(generatedMetadata);
    } catch (e: any) {
      setError(e.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handleGenerateOutline = useCallback(async (data: ArticleFormData) => {
      setError(null);
      setIsLoading(true);
      setLoadingMessage('Structuring your article outline...');

      try {
          const outline = await generateArticleOutline(data.topic, data.keywords, data.domain, data.context);
          setArticleOutline(outline);
      } catch (e: any) {
          setError(e.message);
      } finally {
          setIsLoading(false);
      }
  }, []);

  const handleWriteArticle = useCallback(async (outline: string, data: ArticleFormData) => {
      setIsLoading(true);
      setLoadingMessage('Alex is writing your article (researching, checking facts, and optimizing images)...');

      if (data.imageFile) {
        const dataUrl = await fileToDataUrl(data.imageFile);
        setCurrentImage(dataUrl);
      } else {
        setCurrentImage(null);
      }

      try {
          const { article, grounding_metadata } = await generateFullArticle(outline, data.topic, data.domain, data.context, data.imageFile);
          setReviewMarkdown(article); // Reuse existing markdown display state
          setGroundingMetadata(grounding_metadata);
          setArticleOutline(null); // Clear outline mode to show result

          setLoadingMessage('Generating publishing pack...');
          const generatedMetadata = await generateMetadata(article);
          setMetadata(generatedMetadata);

      } catch (e: any) {
          setError(e.message);
      } finally {
          setIsLoading(false);
      }
  }, []);

  const handleFactCheck = useCallback(async () => {
    if (!reviewMarkdown) return;
    setIsLoading(true);
    setLoadingMessage('Fact-checking and refining your content...');
    setError(null);
    setFactCheckReport(null);
    setMetadata(null);

    try {
      const { report, refinedReview, grounding_metadata } = await factCheckReview(reviewMarkdown);
      setFactCheckReport(report);
      setReviewMarkdown(refinedReview);
      setGroundingMetadata(grounding_metadata);
      setLoadingMessage('Re-generating publishing pack...');
      const generatedMetadata = await generateMetadata(refinedReview);
      setMetadata(generatedMetadata);
    } catch (e: any) {
      setError(e.message);
    } finally {
      setIsLoading(false);
    }
  }, [reviewMarkdown]);

  const handleEditToggle = () => setIsEditing(prev => !prev);

  const handleSaveEdit = async (newMarkdown: string) => {
    setReviewMarkdown(newMarkdown);
    setIsEditing(false);
    setLoadingMessage('Re-generating publishing pack based on your edits...');
    setIsLoading(true);
    try {
      const generatedMetadata = await generateMetadata(newMarkdown);
      setMetadata(generatedMetadata);
    } catch(e: any) {
      setError(e.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDownload = (type: 'pdf' | 'md' | 'ghost' | 'json' | 'jsonl') => {
    const fileNameBase = getFileNameBase(reviewMarkdown);
    switch(type) {
      case 'pdf':
        const reviewElement = document.getElementById('review-output-content');
        if(reviewElement) downloadPdf(reviewElement, fileNameBase);
        break;
      case 'md':
        if(reviewMarkdown) downloadFile(reviewMarkdown, `${fileNameBase}.md`, 'text/markdown');
        break;
      case 'json':
        if(metadata) downloadFile(JSON.stringify(metadata, null, 2), `${fileNameBase}.json`, 'application/json');
        break;
      case 'jsonl':
        if(metadata) downloadFile(JSON.stringify(metadata), `${fileNameBase}.jsonl`, 'application/jsonl');
        break;
      case 'ghost':
        // This is handled within the MetadataDisplay component currently
        break;
    }
  };

  return (
    <div className="min-h-screen p-4 sm:p-6 lg:p-8">
      <div className="max-w-4xl mx-auto">
        <Header />

        {/* Mode Switcher Tabs */}
        <div className="mt-8 flex justify-center border-b border-gray-200">
             <button
                className={`px-6 py-3 font-bold text-sm sm:text-base border-b-2 transition-colors ${mode === 'review' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-brand-charcoal'}`}
                onClick={() => handleModeSwitch('review')}
             >
                Review Generator
             </button>
             <button
                className={`px-6 py-3 font-bold text-sm sm:text-base border-b-2 transition-colors ${mode === 'article' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-brand-charcoal'}`}
                onClick={() => handleModeSwitch('article')}
             >
                Article & Silo Creator
             </button>
        </div>

        <main className="mt-6">
          <section className="bg-brand-surface p-6 rounded-lg shadow-md">
            {mode === 'review' ? (
                <ReviewForm onGenerate={handleGenerateReview} isLoading={isLoading} />
            ) : (
                <ArticleForm 
                    onGenerateOutline={handleGenerateOutline} 
                    onGenerateArticle={handleWriteArticle}
                    isLoading={isLoading} 
                    outline={articleOutline}
                />
            )}
          </section>

          {isLoading && <Loader message={loadingMessage} />}
          {error && <ErrorDisplay message={error} />}

          {(reviewMarkdown || factCheckReport) && !isLoading && !articleOutline && (
            <section className="mt-8 bg-brand-surface p-6 rounded-lg shadow-md">
                {factCheckReport && <FactCheckReport report={factCheckReport} />}
                {reviewMarkdown && (
                    <ReviewOutput 
                        markdown={reviewMarkdown} 
                        isEditing={isEditing} 
                        onSave={handleSaveEdit} 
                        currentImage={currentImage}
                    />
                )}
                <ActionButtons 
                    isReviewGenerated={!!reviewMarkdown}
                    onFactCheck={handleFactCheck}
                    onEdit={handleEditToggle}
                    isEditing={isEditing}
                    onDownload={handleDownload}
                />
                {groundingMetadata && <SourceList metadata={groundingMetadata} />}
                {metadata && <MetadataDisplay metadata={metadata} reviewMarkdown={reviewMarkdown ?? ''}/>}
            </section>
          )}
        </main>
      </div>
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { markdownToHtml } from '../utils/markdown';

interface ReviewOutputProps {
  markdown: string;
  isEditing: boolean;
  onSave: (newMarkdown: string) => void;
  currentImage: string | null;
}

export const ReviewOutput: React.FC<ReviewOutputProps> = ({ markdown, isEditing, onSave, currentImage }) => {
  const [editedMarkdown, setEditedMarkdown] = useState(markdown);

  useEffect(() => {
    setEditedMarkdown(markdown);
  }, [markdown]);

  if (isEditing) {
    return (
      <div className="mt-6">
        <textarea
          value={editedMarkdown}
          onChange={(e) => setEditedMarkdown(e.target.value)}
          className="w-full h-96 p-3 font-mono text-sm border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-brand-primary focus:border-brand-primary"
        />
        <button
          onClick={() => onSave(editedMarkdown)}
          className="mt-2 px-4 py-2 font-bold text-white bg-brand-success rounded-md shadow-sm hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500"
        >
          Save Changes
        </button>
      </div>
    );
  }

  // Handle Image Injection
  let processedMarkdown = markdown;
  let imageRenderedInMarkdown = false;

  if (currentImage) {
    // 1. Check if the AI generated the specific placeholder (Article Mode)
    if (processedMarkdown.includes('(<User Uploaded Image>)')) {
        processedMarkdown = processedMarkdown.replace(/\(<User Uploaded Image>\)/g, `(${currentImage})`);
        imageRenderedInMarkdown = true;
    }
    // 2. Fallback: check if the AI was clever and used a generic placeholder
    else if (processedMarkdown.includes('](image)')) {
         processedMarkdown = processedMarkdown.replace(/\]\(image\)/g, `](${currentImage})`);
         imageRenderedInMarkdown = true;
    }
  }

  const htmlContent = markdownToHtml(processedMarkdown);

  return (
    <div id="review-output-content" className="mt-6">
        {/* If we have an image, but it wasn't replaced in the Markdown (e.g. Review Mode), prepend it visually */}
        {currentImage && !imageRenderedInMarkdown && (
            <div className="mb-8">
                <img 
                    src={currentImage} 
                    alt="Analyzed eBike" 
                    className="w-full max-w-2xl mx-auto rounded-lg shadow-md object-cover" 
                    style={{ maxHeight: '500px' }}
                />
            </div>
        )}

        <div 
            className="prose max-w-none"
            dangerouslySetInnerHTML={{ __html: htmlContent }} 
        />
    </div>
  );
};

