export async function generateMetadata(reviewMarkdown: string): Promise<Metadata> {
    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: `${PUBLISHING_PACK_PROMPT}\n\n${reviewMarkdown}`,
            config: {
                responseMimeType: "application/json",
            }
        });

        const jsonText = response.text.trim();
        const metadata = JSON.parse(jsonText) as Metadata;
        return metadata;

    } catch (error: any) {
        console.error("Error generating metadata:", error);
        throw new Error(`Failed to generate metadata: ${error.message}`);
    }
}

export async function generateArticleOutline(topic: string, keywords: string, domain: string, context: string): Promise<string> {
    // Tavily search for high level topic info
    const tavilyContext = await searchTavily(`${topic} ${keywords} ${domain} key facts safety ratings recalls`);

    const prompt = `${ARTICLE_OUTLINE_PROMPT}

    Topic: ${topic}
    Keywords: ${keywords}
    Manufacturer Domain: ${domain}
    Context/Research Notes: ${context}

    ${tavilyContext}
    `;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: prompt,
        });
        return response.text;
    } catch (error: any) {
         console.error("Error generating outline:", error);
        throw new Error(`Failed to generate outline: ${error.message}`);
    }
}

export async function generateFullArticle(outline: string, topic: string, domain: string, context: string, imageFile: File | null): Promise<{ article: string, grounding_metadata: GroundingMetadata | null }> {
    const parts: any[] = [
        { text: ARTICLE_GENERATION_PROMPT }
    ];

    // Deep research for the article body
    const tavilyContext = await searchTavily(`${topic} ${domain} detailed guide statistics safety standards`);

    const inputData = `
    Topic: ${topic}
    Manufacturer Domain: ${domain}
    Additional Context: ${context}

    ${tavilyContext}

    APPROVED OUTLINE:
    ${outline}
    `;

    parts.push({ text: inputData });

    if (imageFile) {
        const imagePart = await fileToGenerativePart(imageFile);
        parts.push(imagePart);
        parts.push({ text: "Use this image for visual analysis and photo journalism description." });
    }

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: { parts },
            config: {
                tools: [{ googleSearch: {} }],
            }
        });

        return { 
            article: response.text, 
            grounding_metadata: response.candidates?.[0]?.groundingMetadata as GroundingMetadata | null 
        };
    } catch (error: any) {
        console.error("Error generating article:", error);
        throw new Error(`Failed to generate article: ${error.message}`);
    }
}

import React, { useState, useCallback } from 'react';
import { Header } from './components/Header';
import { ReviewForm } from './components/ReviewForm';
import { ArticleForm, ArticleFormData } from './components/ArticleForm';
import { Loader } from './components/Loader';
import { ErrorDisplay } from './components/ErrorDisplay';
import { FactCheckReport } from './components/FactCheckReport';
import { ReviewOutput } from './components/ReviewOutput';
import { ActionButtons } from './components/ActionButtons';
import { SourceList } from './components/SourceList';
import { MetadataDisplay } from './components/MetadataDisplay';
import { generateReview, factCheckReview, generateMetadata, generateArticleOutline, generateFullArticle, generateEbikeImage } from './services/geminiService';
import type { GroundingMetadata, Metadata } from './types';
import { downloadFile, downloadPdf, getFileNameBase } from './utils/download';

type AppMode = 'review' | 'article';

function App() {
  const [mode, setMode] = useState<AppMode>('review');
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');
  const [error, setError] = useState<string | null>(null);

  // Review Mode State
  const [reviewMarkdown, setReviewMarkdown] = useState<string | null>(null);
  const [factCheckReport, setFactCheckReport] = useState<string | null>(null);
  const [groundingMetadata, setGroundingMetadata] = useState<GroundingMetadata | null>(null);
  const [metadata, setMetadata] = useState<Metadata | null>(null);
  const [isEditing, setIsEditing] = useState<boolean>(false);
  const [currentImage, setCurrentImage] = useState<string | null>(null);

  // Article Mode State
  const [articleOutline, setArticleOutline] = useState<string | null>(null);

  const clearResults = () => {
    setError(null);
    setReviewMarkdown(null);
    setFactCheckReport(null);
    setGroundingMetadata(null);
    setMetadata(null);
    setIsEditing(false);
    setArticleOutline(null);
    setCurrentImage(null);
  };

  const handleModeSwitch = (newMode: AppMode) => {
    if (newMode !== mode) {
        setMode(newMode);
        // Optional: clear results on switch or keep them? 
        // Keeping them allows user to switch back and forth without losing work immediately.
        setError(null);
    }
  };

  const fileToDataUrl = (file: File): Promise<string> => {
    return new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(file);
    });
  };

  const handleGenerateReview = useCallback(async (bikeName: string, imageFile: File | null) => {
    clearResults();
    setIsLoading(true);

    if (!process.env.API_KEY) {
        setError("API_KEY environment variable not set. Please configure it to use the application.");
        setIsLoading(false);
        return;
    }

    // Handle Image Logic: Upload vs Generate
    if (imageFile) {
        const dataUrl = await fileToDataUrl(imageFile);
        setCurrentImage(dataUrl);
    } else {
        setLoadingMessage('Generating a unique AI feature image for this bike...');
        try {
            const generatedImage = await generateEbikeImage(bikeName);
            if (generatedImage) setCurrentImage(generatedImage);
        } catch (e) {
             console.warn("Failed to generate image", e);
             // Non-fatal error, proceed with review generation
        }
    }

    setLoadingMessage('Researching and writing your review...');

    try {
      const { review, grounding_metadata } = await generateReview(bikeName, imageFile);
      setReviewMarkdown(review);
      setGroundingMetadata(grounding_metadata);
      setLoadingMessage('Generating publishing pack...');
      const generatedMetadata = await generateMetadata(review);
      setMetadata(generatedMetadata);
    } catch (e: any) {
      setError(e.message);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handleGenerateOutline = useCallback(async (data: ArticleFormData) => {
      setError(null);
      setIsLoading(true);
      setLoadingMessage('Structuring your article outline...');

      try {
          const outline = await generateArticleOutline(data.topic, data.keywords, data.domain, data.context);
          setArticleOutline(outline);
      } catch (e: any) {
          setError(e.message);
      } finally {
          setIsLoading(false);
      }
  }, []);

  const handleWriteArticle = useCallback(async (outline: string, data: ArticleFormData) => {
      setIsLoading(true);

      // Handle Image Logic: Upload vs Generate
      if (data.imageFile) {
        const dataUrl = await fileToDataUrl(data.imageFile);
        setCurrentImage(dataUrl);
      } else {
         setLoadingMessage('Generating a custom editorial image for your article...');
         try {
            const generatedImage = await generateEbikeImage(`${data.topic} ${data.keywords}`);
            if (generatedImage) setCurrentImage(generatedImage);
            else setCurrentImage(null);
         } catch(e) {
             console.warn("Image generation failed", e);
             setCurrentImage(null);
         }
      }

      setLoadingMessage('Alex is writing your article (researching, checking facts, and optimizing images)...');

      try {
          const { article, grounding_metadata } = await generateFullArticle(outline, data.topic, data.domain, data.context, data.imageFile);
          setReviewMarkdown(article); // Reuse existing markdown display state
          setGroundingMetadata(grounding_metadata);
          setArticleOutline(null); // Clear outline mode to show result

          setLoadingMessage('Generating publishing pack...');
          const generatedMetadata = await generateMetadata(article);
          setMetadata(generatedMetadata);

      } catch (e: any) {
          setError(e.message);
      } finally {
          setIsLoading(false);
      }
  }, []);

  const handleFactCheck = useCallback(async () => {
    if (!reviewMarkdown) return;
    setIsLoading(true);
    setLoadingMessage('Fact-checking and refining your content...');
    setError(null);
    setFactCheckReport(null);
    setMetadata(null);

    try {
      const { report, refinedReview, grounding_metadata } = await factCheckReview(reviewMarkdown);
      setFactCheckReport(report);
      setReviewMarkdown(refinedReview);
      setGroundingMetadata(grounding_metadata);
      setLoadingMessage('Re-generating publishing pack...');
      const generatedMetadata = await generateMetadata(refinedReview);
      setMetadata(generatedMetadata);
    } catch (e: any) {
      setError(e.message);
    } finally {
      setIsLoading(false);
    }
  }, [reviewMarkdown]);

  const handleEditToggle = () => setIsEditing(prev => !prev);

  const handleSaveEdit = async (newMarkdown: string) => {
    setReviewMarkdown(newMarkdown);
    setIsEditing(false);
    setLoadingMessage('Re-generating publishing pack based on your edits...');
    setIsLoading(true);
    try {
      const generatedMetadata = await generateMetadata(newMarkdown);
      setMetadata(generatedMetadata);
    } catch(e: any) {
      setError(e.message);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDownload = (type: 'pdf' | 'md' | 'ghost' | 'json' | 'jsonl') => {
    const fileNameBase = getFileNameBase(reviewMarkdown);
    switch(type) {
      case 'pdf':
        const reviewElement = document.getElementById('review-output-content');
        if(reviewElement) downloadPdf(reviewElement, fileNameBase);
        break;
      case 'md':
        if(reviewMarkdown) downloadFile(reviewMarkdown, `${fileNameBase}.md`, 'text/markdown');
        break;
      case 'json':
        if(metadata) downloadFile(JSON.stringify(metadata, null, 2), `${fileNameBase}.json`, 'application/json');
        break;
      case 'jsonl':
        if(metadata) downloadFile(JSON.stringify(metadata), `${fileNameBase}.jsonl`, 'application/jsonl');
        break;
      case 'ghost':
        // This is handled within the MetadataDisplay component currently
        break;
    }
  };

  return (
    <div className="min-h-screen p-4 sm:p-6 lg:p-8">
      <div className="max-w-4xl mx-auto">
        <Header />

        {/* Mode Switcher Tabs */}
        <div className="mt-8 flex justify-center border-b border-gray-200">
             <button
                className={`px-6 py-3 font-bold text-sm sm:text-base border-b-2 transition-colors ${mode === 'review' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-brand-charcoal'}`}
                onClick={() => handleModeSwitch('review')}
             >
                Review Generator
             </button>
             <button
                className={`px-6 py-3 font-bold text-sm sm:text-base border-b-2 transition-colors ${mode === 'article' ? 'border-brand-primary text-brand-primary' : 'border-transparent text-gray-500 hover:text-brand-charcoal'}`}
                onClick={() => handleModeSwitch('article')}
             >
                Article & Silo Creator
             </button>
        </div>

        <main className="mt-6">
          <section className="bg-brand-surface p-6 rounded-lg shadow-md">
            {mode === 'review' ? (
                <ReviewForm onGenerate={handleGenerateReview} isLoading={isLoading} />
            ) : (
                <ArticleForm 
                    onGenerateOutline={handleGenerateOutline} 
                    onGenerateArticle={handleWriteArticle}
                    isLoading={isLoading} 
                    outline={articleOutline}
                />
            )}
          </section>

          {isLoading && <Loader message={loadingMessage} />}
          {error && <ErrorDisplay message={error} />}

          {(reviewMarkdown || factCheckReport) && !isLoading && !articleOutline && (
            <section className="mt-8 bg-brand-surface p-6 rounded-lg shadow-md">
                {factCheckReport && <FactCheckReport report={factCheckReport} />}
                {reviewMarkdown && (
                    <ReviewOutput 
                        markdown={reviewMarkdown} 
                        isEditing={isEditing} 
                        onSave={handleSaveEdit} 
                        currentImage={currentImage}
                    />
                )}
                <ActionButtons 
                    isReviewGenerated={!!reviewMarkdown}
                    onFactCheck={handleFactCheck}
                    onEdit={handleEditToggle}
                    isEditing={isEditing}
                    onDownload={handleDownload}
                />
                {groundingMetadata && <SourceList metadata={groundingMetadata} />}
                {metadata && <MetadataDisplay metadata={metadata} reviewMarkdown={reviewMarkdown ?? ''}/>}
            </section>
          )}
        </main>
      </div>
    </div>
  );
}

export default App;

import React from 'react';

interface ActionButtonsProps {
  isReviewGenerated: boolean;
  onFactCheck: () => void;
  onEdit: () => void;
  isEditing: boolean;
  onDownload: (type: 'pdf' | 'md' | 'json' | 'jsonl' | 'html') => void;
}

export const ActionButtons: React.FC<ActionButtonsProps> = ({ isReviewGenerated, onFactCheck, onEdit, isEditing, onDownload }) => {
  if (!isReviewGenerated) return null;

  const baseButtonClass = "px-4 py-2 text-sm font-semibold rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-offset-2 transition-colors";
  const primaryButtonClass = `${baseButtonClass} text-white bg-brand-secondary hover:bg-brand-secondary-dark focus:ring-brand-secondary`;
  const editButtonClass = isEditing 
    ? `${baseButtonClass} text-white bg-brand-primary hover:bg-brand-primary-dark focus:ring-brand-primary` 
    : primaryButtonClass;

  return (
    <div className="mt-8 pt-6 border-t border-gray-200">
      <h3 className="text-lg font-bold text-brand-charcoal mb-4">Actions</h3>
      <div className="flex flex-wrap gap-3">
        <button onClick={onFactCheck} className={primaryButtonClass}>Fact-Check & Refine</button>
        <button onClick={onEdit} className={editButtonClass}>{isEditing ? 'Cancel Edit' : 'Edit Review'}</button>
        <button onClick={() => onDownload('pdf')} className={primaryButtonClass}>Download PDF</button>
        <button onClick={() => onDownload('html')} className={primaryButtonClass}>Download HTML</button>
        <button onClick={() => onDownload('md')} className={primaryButtonClass}>Download Markdown</button>
        <button onClick={() => onDownload('json')} className={primaryButtonClass}>Download JSON</button>
      </div>
    </div>
  );
};

import React from 'react';
import type { Metadata } from '../types';
import { downloadFile, getFileNameBase } from '../utils/download';
import { markdownToHtml } from '../utils/markdown';

interface MetadataDisplayProps {
  metadata: Metadata;
  reviewMarkdown: string;
  currentImage?: string | null;
}

interface CopyButtonProps {
  textToCopy: string;
  label?: string;
  className?: string;
}

const CopyButton: React.FC<CopyButtonProps> = ({ 
  textToCopy, 
  label = 'Copy', 
  className = "text-xs bg-gray-200 hover:bg-gray-300 text-gray-700 font-semibold py-1 px-2 rounded" 
}) => {
    const [copied, setCopied] = React.useState(false);

    const handleCopy = () => {
        navigator.clipboard.writeText(textToCopy).then(() => {
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        });
    };

    return (
        <button onClick={handleCopy} className={className}>
            {copied ? 'Copied!' : label}
        </button>
    );
}

export const MetadataDisplay: React.FC<MetadataDisplayProps> = ({ metadata, reviewMarkdown, currentImage }) => {
  if (!metadata) return null;

  const fullMarkdown = metadata.post_markdown_lines?.join('\n') ?? reviewMarkdown;
  const bodyHtml = markdownToHtml(fullMarkdown);

  const reviewSchemaLd = {
    "@context": "https://schema.org",
    "@type": "Review",
    "itemReviewed": {
        "@type": "Product",
        "name": metadata.review_schema.itemReviewed.name,
        "description": metadata.review_schema.itemReviewed.description,
        "image": currentImage || metadata.feature_image_url
    },
    "reviewRating": {
        "@type": "Rating",
        "ratingValue": metadata.review_schema.reviewRating.ratingValue,
        "bestRating": metadata.review_schema.reviewRating.bestRating
