    "author": {
        "@type": "Person",
        "name": metadata.review_schema.author.name
    },
    "positiveNotes": {
        "@type": "ItemList",
        "itemListElement": metadata.review_schema.positiveNotes.map((note, index) => ({ "@type": "ListItem", "position": index + 1, "name": note }))
