            <div className="flex justify-between items-center mb-2">
                <h4 className="font-semibold text-brand-secondary">Full Post Expert HTML</h4>
                <div className="flex gap-2">
                    <CopyButton textToCopy={expertHtml} label="Copy HTML" />
